// // When a is 2, q should be 1f96; when a is 0, q should be f776; when a is 1, q should be 9094; when a is 5, q should be 215f; when a is 4, q should be 65f6; when a is 7, q should be 9408; when a is 3, q should be 1d66; when a is 6, q should be 141c.
module top_module (
    input [2:0] a,
    output reg [15:0] q
);  always @(*)
    case (a)
      0: q = 16'hf776;
      1: q = 16'h9094;
      2: q = 16'h1f96;
      3: q = 16'h1d66;
      4: q = 16'h65f6;
      5: q = 16'h215f;
      6: q = 16'h141c;
      7: q = 16'h9408;
    endcase

endmodule
